    /**
     * Get all of CHIP_RESET's bit fields.
     *
     * (read-write) Chip reset control and status
     */
    inline void get_CHIP_RESET(bool &DOUBLE_TAP, bool &RESCUE_FLAG,
                               bool &HAD_POR, bool &HAD_BOR, bool &HAD_RUN_LOW,
                               bool &HAD_DP_RESET_REQ, bool &HAD_RESCUE,
                               bool &HAD_WATCHDOG_RESET_POWMAN_ASYNC,
                               bool &HAD_WATCHDOG_RESET_POWMAN,
                               bool &HAD_WATCHDOG_RESET_SWCORE,
                               bool &HAD_SWCORE_PD, bool &HAD_GLITCH_DETECT,
                               bool &HAD_HZD_SYS_RESET_REQ,
                               bool &HAD_WATCHDOG_RESET_RSM) volatile
    {
        uint32_t curr = CHIP_RESET;

        DOUBLE_TAP = curr & 1u;
        RESCUE_FLAG = curr & (1u << 4u);
        HAD_POR = curr & (1u << 16u);
        HAD_BOR = curr & (1u << 17u);
        HAD_RUN_LOW = curr & (1u << 18u);
        HAD_DP_RESET_REQ = curr & (1u << 19u);
        HAD_RESCUE = curr & (1u << 21u);
        HAD_WATCHDOG_RESET_POWMAN_ASYNC = curr & (1u << 22u);
        HAD_WATCHDOG_RESET_POWMAN = curr & (1u << 23u);
        HAD_WATCHDOG_RESET_SWCORE = curr & (1u << 24u);
        HAD_SWCORE_PD = curr & (1u << 25u);
        HAD_GLITCH_DETECT = curr & (1u << 26u);
        HAD_HZD_SYS_RESET_REQ = curr & (1u << 27u);
        HAD_WATCHDOG_RESET_RSM = curr & (1u << 28u);
    }

    /**
     * Set all of CHIP_RESET's bit fields.
     *
     * (read-write) Chip reset control and status
     */
    inline void set_CHIP_RESET(bool DOUBLE_TAP, bool RESCUE_FLAG) volatile
    {
        uint32_t curr = CHIP_RESET;

        curr &= ~(0b1u);
        curr |= (DOUBLE_TAP & 0b1u);
        curr &= ~(0b1u << 4u);
        curr |= (RESCUE_FLAG & 0b1u) << 4u;

        CHIP_RESET = curr;
    }

