    /**
     * Get all of SEQ_CFG's bit fields.
     *
     * (read-write) For configuration of the power sequencer
     *                     Writes are ignored while POWMAN_STATE_CHANGING=1
     */
    inline void get_SEQ_CFG(bool &HW_PWRUP_SRAM1, bool &HW_PWRUP_SRAM0,
                            bool &USE_VREG_LP, bool &USE_VREG_HP,
                            bool &USE_BOD_LP, bool &USE_BOD_HP,
                            bool &RUN_LPOSC_IN_LP, bool &USE_FAST_POWCK,
                            bool &USING_VREG_LP, bool &USING_BOD_LP,
                            bool &USING_FAST_POWCK) volatile
    {
        uint32_t curr = SEQ_CFG;

        HW_PWRUP_SRAM1 = curr & 1u;
        HW_PWRUP_SRAM0 = curr & (1u << 1u);
        USE_VREG_LP = curr & (1u << 4u);
        USE_VREG_HP = curr & (1u << 5u);
        USE_BOD_LP = curr & (1u << 6u);
        USE_BOD_HP = curr & (1u << 7u);
        RUN_LPOSC_IN_LP = curr & (1u << 8u);
        USE_FAST_POWCK = curr & (1u << 12u);
        USING_VREG_LP = curr & (1u << 16u);
        USING_BOD_LP = curr & (1u << 17u);
        USING_FAST_POWCK = curr & (1u << 20u);
    }

    /**
     * Set all of SEQ_CFG's bit fields.
     *
     * (read-write) For configuration of the power sequencer
     *                     Writes are ignored while POWMAN_STATE_CHANGING=1
     */
    inline void set_SEQ_CFG(bool HW_PWRUP_SRAM1, bool HW_PWRUP_SRAM0,
                            bool USE_VREG_LP, bool USE_VREG_HP,
                            bool USE_BOD_LP, bool USE_BOD_HP,
                            bool RUN_LPOSC_IN_LP, bool USE_FAST_POWCK) volatile
    {
        uint32_t curr = SEQ_CFG;

        curr &= ~(0b1u);
        curr |= (HW_PWRUP_SRAM1 & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (HW_PWRUP_SRAM0 & 0b1u) << 1u;
        curr &= ~(0b1u << 4u);
        curr |= (USE_VREG_LP & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (USE_VREG_HP & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (USE_BOD_LP & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (USE_BOD_HP & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (RUN_LPOSC_IN_LP & 0b1u) << 8u;
        curr &= ~(0b1u << 12u);
        curr |= (USE_FAST_POWCK & 0b1u) << 12u;

        SEQ_CFG = curr;
    }

