    /**
     * Get STATE's REQ field.
     *
     * This is written by software or hardware to request a new power state
     */
    inline uint8_t get_STATE_REQ() volatile
    {
        return (STATE >> 4u) & 0xfu;
    }

    /**
     * Set STATE's REQ field.
     *
     * This is written by software or hardware to request a new power state
     */
    inline void set_STATE_REQ(uint8_t value) volatile
    {
        uint32_t curr = STATE;

        curr &= ~(0xfu << 4u);
        curr |= (value & 0xfu) << 4u;

        STATE = curr;
    }

