    /**
     * Get all of STATE's bit fields.
     *
     * (read-write) This register controls the power state of the 4 power
     * domains. The current power state is indicated in POWMAN_STATE_CURRENT
     * which is read-only. To change the state, write to POWMAN_STATE_REQ. The
     * coding of POWMAN_STATE_CURRENT & POWMAN_STATE_REQ corresponds to the
     * power states defined in the datasheet: bit 3 = SWCORE bit 2 = XIP cache
     *                     bit 1 = SRAM0
     *                     bit 0 = SRAM1
     *                     0 = powered up
     *                     1 = powered down
     *                     When POWMAN_STATE_REQ is written, the
     * POWMAN_STATE_WAITING flag is set while the Power Manager determines what
     * is required. If an invalid transition is requested the Power Manager
     * will still register the request in POWMAN_STATE_REQ but will also set
     * the POWMAN_BAD_REQ flag. It will then implement the power-up requests
     * and ignore the power down requests. To do nothing would risk entering an
     * unrecoverable lock-up state. Invalid requests are: any combination of
     * power up and power down requests any request that results in swcore
     * being powered and xip unpowered If the request is to power down the
     * switched-core domain then POWMAN_STATE_WAITING stays active until the
     * processors halt. During this time the POWMAN_STATE_REQ field can be
     * re-written to change or cancel the request. When the power state
     * transition begins the POWMAN_STATE_WAITING_flag is cleared, the
     * POWMAN_STATE_CHANGING flag is set and POWMAN register writes are ignored
     * until the transition completes.
     */
    inline void get_STATE(uint8_t &CURRENT, uint8_t &REQ, bool &REQ_IGNORED,
                          bool &PWRUP_WHILE_WAITING, bool &BAD_SW_REQ,
                          bool &BAD_HW_REQ, bool &WAITING,
                          bool &CHANGING) volatile
    {
        uint32_t curr = STATE;

        CURRENT = curr & 0xfu;
        REQ = (curr >> 4u) & 0xfu;
        REQ_IGNORED = curr & (1u << 8u);
        PWRUP_WHILE_WAITING = curr & (1u << 9u);
        BAD_SW_REQ = curr & (1u << 10u);
        BAD_HW_REQ = curr & (1u << 11u);
        WAITING = curr & (1u << 12u);
        CHANGING = curr & (1u << 13u);
    }

    /**
     * Set all of STATE's bit fields.
     *
     * (read-write) This register controls the power state of the 4 power
     * domains. The current power state is indicated in POWMAN_STATE_CURRENT
     * which is read-only. To change the state, write to POWMAN_STATE_REQ. The
     * coding of POWMAN_STATE_CURRENT & POWMAN_STATE_REQ corresponds to the
     * power states defined in the datasheet: bit 3 = SWCORE bit 2 = XIP cache
     *                     bit 1 = SRAM0
     *                     bit 0 = SRAM1
     *                     0 = powered up
     *                     1 = powered down
     *                     When POWMAN_STATE_REQ is written, the
     * POWMAN_STATE_WAITING flag is set while the Power Manager determines what
     * is required. If an invalid transition is requested the Power Manager
     * will still register the request in POWMAN_STATE_REQ but will also set
     * the POWMAN_BAD_REQ flag. It will then implement the power-up requests
     * and ignore the power down requests. To do nothing would risk entering an
     * unrecoverable lock-up state. Invalid requests are: any combination of
     * power up and power down requests any request that results in swcore
     * being powered and xip unpowered If the request is to power down the
     * switched-core domain then POWMAN_STATE_WAITING stays active until the
     * processors halt. During this time the POWMAN_STATE_REQ field can be
     * re-written to change or cancel the request. When the power state
     * transition begins the POWMAN_STATE_WAITING_flag is cleared, the
     * POWMAN_STATE_CHANGING flag is set and POWMAN register writes are ignored
     * until the transition completes.
     */
    inline void set_STATE(uint8_t REQ, bool REQ_IGNORED,
                          bool PWRUP_WHILE_WAITING) volatile
    {
        uint32_t curr = STATE;

        curr &= ~(0xfu << 4u);
        curr |= (REQ & 0xfu) << 4u;
        curr &= ~(0b1u << 8u);
        curr |= (REQ_IGNORED & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (PWRUP_WHILE_WAITING & 0b1u) << 9u;

        STATE = curr;
    }

