    /**
     * Get all of TIMER's bit fields.
     */
    inline void get_TIMER(bool &NONSEC_WRITE, bool &RUN, bool &ALARM_ENAB,
                          bool &PWRUP_ON_ALARM, bool &ALARM,
                          bool &USE_GPIO_1HZ, bool &USING_XOSC,
                          bool &USING_LPOSC, bool &USING_GPIO_1KHZ,
                          bool &USING_GPIO_1HZ) volatile
    {
        uint32_t curr = TIMER;

        NONSEC_WRITE = curr & 1u;
        RUN = curr & (1u << 1u);
        ALARM_ENAB = curr & (1u << 4u);
        PWRUP_ON_ALARM = curr & (1u << 5u);
        ALARM = curr & (1u << 6u);
        USE_GPIO_1HZ = curr & (1u << 13u);
        USING_XOSC = curr & (1u << 16u);
        USING_LPOSC = curr & (1u << 17u);
        USING_GPIO_1KHZ = curr & (1u << 18u);
        USING_GPIO_1HZ = curr & (1u << 19u);
    }

