    {
        uint32_t curr = BOOTDIS;

        curr &= ~(0b1u);
        curr |= (NOW & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (NEXT & 0b1u) << 1u;

        BOOTDIS = curr;
    }

